module RefModule (
    input wire [7:0] data_in,
    input wire [7:0] expected_checksum,
    output reg [7:0] calculated_checksum,
    output reg is_valid
);
    integer obf_i;
    always @(*) begin
        calculated_checksum = 0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            calculated_checksum = calculated_checksum + data_in[obf_i];
        end
        calculated_checksum = calculated_checksum % 256;
        is_valid = (calculated_checksum == expected_checksum);
    end
endmodule
